using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    // ── CalculateTotal: inline cases with DataRow ──────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 3, 0.0, 30.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 4, 0.08, 110.16, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 5, 0.10, 0.00, DisplayName = "Zero unit price")]
    [DataRow(99.99, 0, 0.20, 0.00, DisplayName = "Zero quantity")]
    [DataRow(10.00, 1, 1.0, 20.00, DisplayName = "100% tax rate")]
    public void CalculateTotal_ValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ── CalculateTotal: richer cases with DynamicData + ValueTuples ───

    [TestMethod]
    [DynamicData(nameof(CalculateTotalEdgeCases))]
    public void CalculateTotal_EdgeCases_ReturnsExpectedTotal(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate, decimal expected)>
        CalculateTotalEdgeCases =>
    [
        (0.01m, 1, 0m, 0.01m),       // smallest meaningful price
        (9999.99m, 100, 0.25m, 1_249_998.75m), // large order with tax
        (1m, 1, 0.0725m, 1.0725m),   // real-world tax rate (7.25%)
    ];

    // ── CalculateTotal: invalid inputs ────────────────────────────────

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, DisplayName = "Negative unit price")]
    public void CalculateTotal_NegativeUnitPrice_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual("unitPrice", ex.ParamName);
    }

    [TestMethod]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity")]
    public void CalculateTotal_NegativeQuantity_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual("quantity", ex.ParamName);
    }

    [TestMethod]
    [DataRow(10.00, 1, -0.01, DisplayName = "Tax rate below 0")]
    [DataRow(10.00, 1, 1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidTaxRate_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual("taxRate", ex.ParamName);
    }

    // ── ApplyDiscount: inline cases with DataRow ──────────────────────

    [TestMethod]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "No discount")]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% off")]
    [DataRow(100.00, 50.0, 50.00, DisplayName = "50% off")]
    [DataRow(100.00, 100.0, 0.00, DisplayName = "100% off (free)")]
    [DataRow(79.99, 25.0, 59.9925, DisplayName = "Fractional result")]
    public void ApplyDiscount_ValidInputs_ReturnsDiscountedPrice(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // ── ApplyDiscount: complex cases with DynamicData + ValueTuples ───

    [TestMethod]
    [DynamicData(nameof(DiscountEdgeCases))]
    public void ApplyDiscount_EdgeCases_ReturnsExpectedPrice(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)>
        DiscountEdgeCases =>
    [
        (0m, 50m, 0m),               // zero price stays zero
        (0.01m, 10m, 0.009m),        // tiny price
        (10_000m, 33.33m, 6_667m),   // large price, non-trivial percent
    ];

    // ── ApplyDiscount: invalid inputs ─────────────────────────────────

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Discount below 0%")]
    [DataRow(100.01, DisplayName = "Discount above 100%")]
    public void ApplyDiscount_InvalidDiscountPercent_Throws(double discountPercent)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }
}

